/* Bluetooth LE Profile Callback Interface - ble_profile.h */
#ifndef BLE_PROFILE_H
#define BLE_PROFILE_H

#include <stdint.h>

typedef enum {
    BLE_EVT_CONNECTED    = 0,
    BLE_EVT_DISCONNECTED = 1,
    BLE_EVT_DATA_RX      = 2,
    BLE_EVT_DATA_TX_DONE = 3
} ble_event_t;

typedef struct {
    uint8_t  conn_handle;
    uint8_t  addr[6];
    uint16_t mtu;
} ble_conn_info_t;

/* BREAKING: Callback signature changed — data and data_len removed from
   the generic callback; callers must now cast event-specific context ptr.
   All existing ble_event_cb_t implementations have wrong signatures. */
typedef void (*ble_event_cb_t)(ble_event_t event,
                               const ble_conn_info_t *conn,
                               void *event_ctx);

void ble_profile_init(ble_event_cb_t callback);
void ble_profile_deinit(void);
int  ble_profile_send(uint8_t conn_handle, const uint8_t *data, uint16_t len);

#endif /* BLE_PROFILE_H */

